import{c as o,Q as t,j as n,m as r}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Known Issues","description":"","frontmatter":{},"headers":[],"relativePath":"known-issues.md","filePath":"known-issues.md","lastUpdated":1778828280000}'),s={name:"known-issues.md"};function a(i,e,c,d,l,p){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="known-issues" tabindex="-1">Known Issues <a class="header-anchor" href="#known-issues" aria-label="Permalink to &quot;Known Issues&quot;">​</a></h1><p>Tracked bugs and design gaps deferred for dedicated follow-up. Entries stay until fixed or explicitly accepted.</p><hr><h2 id="toctou-on-3-concurrent-job-cap" tabindex="-1">TOCTOU on 3-concurrent job cap <a class="header-anchor" href="#toctou-on-3-concurrent-job-cap" aria-label="Permalink to &quot;TOCTOU on 3-concurrent job cap&quot;">​</a></h2><p><strong>Symptom:</strong> Two concurrent POSTs to job-start endpoints can both pass the <code>CountRunningJobs &lt; 3</code> check and both insert, exceeding the 3-concurrent cap.</p><p><strong>Scope:</strong> Pre-existing in every start endpoint (<a href="./internal/handler/migrations/handler.go">internal/handler/migrations/handler.go</a>) — not introduced by rerun work.</p><p><strong>Cause:</strong> <code>CountRunningJobs</code> runs outside the insert transaction. Race window between count and insert.</p><p><strong>Severity:</strong> Low. Cap is soft guard, not safety-critical. Race window tiny.</p><p><strong>Fix options:</strong></p><ul><li>pg advisory lock keyed on tenant/instance around count+insert</li><li>COUNT + INSERT in single tx with SERIALIZABLE isolation</li><li>Unique partial index on <code>(status)</code> where <code>status=&#39;running&#39;</code> — not trivial given cap=3, not 1</li></ul><p><strong>Status:</strong> Deferred. Fix in dedicated PR touching all start endpoints.</p><hr><h2 id="instance-replace-resume-state-dependency" tabindex="-1"><code>instance_replace</code> Resume State Dependency <a class="header-anchor" href="#instance-replace-resume-state-dependency" aria-label="Permalink to &quot;`instance_replace` Resume State Dependency&quot;">​</a></h2><p><strong>Symptom:</strong> Rerunning an <code>instance_replace</code> job that failed a long time ago (e.g., &gt;9 months) might lose its progress and re-migrate every tenant from scratch.</p><p><strong>Scope:</strong> <code>loadInheritedInstanceReplaceResults</code> in <a href="./internal/worker/executor_instance_replace.go">executor_instance_replace.go</a>.</p><p><strong>Cause:</strong> The &quot;what succeeded&quot; list for <code>instance_replace</code> is stored in the <code>job_artifacts</code> table. While no SQL-level TTL exists today, the disk-file cleanup worker (<a href="./internal/worker/cleanup.go">internal/worker/cleanup.go</a>) has a misleading comment claiming artifacts have MongoDB TTLs. If a global retention policy is ever added to sweep <code>job_artifacts</code>, <code>instance_replace</code> resume logic will break while other jobs (import/clone) remain safe since their resume state is in the core <code>jobs</code> table.</p><p><strong>Severity:</strong> Low. No data loss; merely redundant work and naming collisions during cloning if not handled.</p><p><strong>Fix options:</strong></p><ul><li>Promote <code>instance_replace_results</code> to a first-class table or a durable storage location (like Azure Fileshare).</li><li>Explicitly whitelist this artifact type from future retention policies.</li></ul><p><strong>Status:</strong> Accepted as design debt. Monitor Postgres storage growth for <code>job_artifacts</code>.</p><hr><h2 id="migration-advisory-lock-breaks-under-transaction-pooled-pgbouncer" tabindex="-1">Migration Advisory Lock Breaks Under Transaction-Pooled PgBouncer <a class="header-anchor" href="#migration-advisory-lock-breaks-under-transaction-pooled-pgbouncer" aria-label="Permalink to &quot;Migration Advisory Lock Breaks Under Transaction-Pooled PgBouncer&quot;">​</a></h2><p><strong>Symptom:</strong> On deploy, multiple API/worker replicas would race on <code>goose.Up</code> and one of them would fail with a <code>goose_db_version</code> unique-constraint violation (SQLSTATE 23505), crash-looping until the losing pods retried.</p><p><strong>Scope:</strong> <a href="./internal/db/migrate.go">internal/db/migrate.go</a> — preflight runs migrations from every process at startup.</p><p><strong>Cause:</strong> Goose v3 legacy API acquires no DB lock. N replicas all read the pending version, all run the migration body, all try to INSERT the same <code>version_id</code> row.</p><p><strong>Fix applied:</strong> Switched to <code>goose.NewProvider(..., WithSessionLocker(lock.NewPostgresSessionLocker()))</code>. The session locker uses <code>pg_advisory_lock</code> — a core Postgres feature, no extension needed. Losing replicas block on the lock, observe the applied version when they acquire it, and exit clean.</p><p><strong>Remaining gotcha:</strong> The session locker relies on the <em>same</em> Postgres connection surviving across statements. This breaks if <code>DATABASE_URL</code> points at a <strong>transaction-pooled PgBouncer</strong> (e.g., Azure Flexible Server&#39;s built-in pooler on port 6432, or pgcat in transaction mode). The pool rotates connections between statements; the advisory lock is released behind goose&#39;s back, and the serialization guarantee silently disappears.</p><p><strong>How to check:</strong></p><ul><li>Confirm <code>DATABASE_URL</code> uses the direct Postgres port (5432 on Azure), not the pooler port (6432).</li><li>If the app runtime ever moves to a transaction-pool DSN, keep the migration DSN on 5432 or switch to <code>lock.NewPostgresTableLocker()</code> which doesn&#39;t depend on session persistence.</li></ul><p><strong>Severity:</strong> Low today (we&#39;re on 5432). Latent footgun if infra changes.</p><p><strong>Status:</strong> Monitor connection routing. Revisit if a pooler is introduced between the app and Postgres.</p>',31)])])}const h=o(s,[["render",a]]);export{u as __pageData,h as default};
